import (
	context "context"
	fern "github.com/datetime-api/fern"
	fernclient "github.com/datetime-api/fern/client"
)

client := fernclient.NewClient()
response, err := client.Endpoints.GetAndReturnWithDatetimeAliasWithDocs(
	context.TODO(),
	&fern.ObjectWithDatetimeAlias{
		DateTime: fern.MustParseDateTime(
			"2023-08-31T14:15:22Z",
		),
		DatetimeAlias: fern.MustParseDateTime(
			"2023-08-31T14:15:22Z",
		),
	},
)
